@@ -1,0 +1,28 @@
+use tokio::sync::mpsc;
+
+pub struct Request {
+    pub id: u64,
+    pub payload: String,
+}
+
+pub struct Reply {
+    pub id: u64,
+    pub body: String,
+    pub is_error: bool,
+}
+
+/// Single-task worker loop: it owns `rx` and is the ONLY consumer of
+/// incoming requests. Each request's handler future is awaited right
+/// here in the loop task.
+pub async fn run(
+    mut rx: mpsc::Receiver<Request>,
+    replies: mpsc::Sender<Reply>,
+    handle: impl Fn(Request) -> std::pin::Pin<Box<dyn std::future::Future<Output = Reply> + Send>>,
+) {
+    while let Some(req) = rx.recv().await {
+        // handle(req) may panic (bad input, handler bug). The future is
+        // awaited inline, so a panic unwinds `run`, drops `rx`, and the
+        // sender half is closed forever — every later request silently
+        // goes nowhere.
+        let reply = handle(req).await;
+        let _ = replies.send(reply).await;
+    }
+}

