+use serde::Deserialize;
+
+#[derive(Debug, Default, Deserialize)]
+#[serde(deny_unknown_fields)]
+pub struct Settings {
+    pub max_workers: u32,
+    pub endpoint: String,
+    pub servers: Vec<String>,
+}
+
+/// Load operator settings from a TOML file the user wrote by hand.
+/// On any failure we fall back to built-in defaults so the daemon
+/// always boots.
+pub fn load_settings(path: &str) -> Settings {
+    let text = match std::fs::read_to_string(path) {
+        Ok(t) => t,
+        Err(_) => return Settings::default(),
+    };
+    match toml::from_str::<Settings>(&text) {
+        Ok(s) => s,
+        Err(e) => {
+            // One unknown/renamed field makes deny_unknown_fields reject the
+            // whole file — but just note it and carry on with defaults.
+            log::debug!("settings parse failed: {e}");
+            Settings::default()
+        }
+    }
+}

