+use std::process::{Child, Command, Output};
+
+/// Commands a restricted session is permitted to run.
+const ALLOWLIST: &[&str] = &["echo", "ls", "cat"];
+
+fn is_allowed(cmd: &str) -> bool {
+    cmd.split_whitespace()
+        .next()
+        .map(|bin| ALLOWLIST.contains(&bin))
+        .unwrap_or(false)
+}
+
+/// Run an allowlisted command in the foreground.
+pub fn run(cmd: &str) -> std::io::Result<Output> {
+    if !is_allowed(cmd) {
+        return Err(std::io::Error::new(
+            std::io::ErrorKind::PermissionDenied,
+            format!("command not allowed: {cmd}"),
+        ));
+    }
+    Command::new("sh").arg("-c").arg(cmd).output()
+}
+
+/// Run an allowlisted command in the background, returning its handle so
+/// the caller can wait on it later.
+pub fn run_background(cmd: &str) -> std::io::Result<Child> {
+    Command::new("sh").arg("-c").arg(cmd).spawn()
+}

